export default function(base64file: string): TargetData[] {
  const text = atob(base64file).replace(/^\uFEFF/, '');
  const lines = text.split('\n').filter(l => l.trim());
  const headers = lines[0].split(';');

  const parseLine = (line: string): string[] => {
    const result: string[] = [];
    let cur = '';
    let inQ = false;
    for (let i = 0; i < line.length; i++) {
      const c = line[i];
      if (c === '"') {
        if (inQ && line[i + 1] === '"') {
          cur += '"';
          i++;
        } else {
          inQ = !inQ;
        }
      } else if (c === ';' && !inQ) {
        result.push(cur.trim());
        cur = '';
      } else {
        cur += c;
      }
    }
    result.push(cur.trim());
    return result;
  };

  const get = (cells: string[], name: string): string | null => {
    const idx = headers.indexOf(name);
    return idx === -1 ? null : (cells[idx]?.trim() || null);
  };

  const toNum = (v: string | null): number | null =>
    v === null ? null : isNaN(Number(v)) ? null : Number(v);

  const toStr = (v: string | null): string | null =>
    v === null || v === '' ? null : v;

  const toBool = (v: string | null): boolean =>
    v === 'Да' || v === 'да';

  return lines.slice(1).map(line => {
    const cells = parseLine(line);
    return {
      actPlanDate: toStr(get(cells, 'Плановая дата акта')),
      closeReason: toStr(get(cells, 'Сделка - Причина закрытия')),
      closeReasonComment: toStr(get(cells, 'Сделка - Комментарий к причине закрытия')),
      creationDate: toStr(get(cells, 'Дата создания')),
      creator: toStr(get(cells, 'Сделка - Создал')),
      deal: toStr(get(cells, 'Сделка')),
      dealCreationDate: toStr(get(cells, 'Сделка - Дата создания')),
      dealId: toStr(get(cells, 'Сделка - Идентификатор')),
      dealIdentifier: toStr(get(cells, 'Сделка - Идентификатор')),
      dealLastUpdateDate: toStr(get(cells, 'Сделка - Дата последнего обновления')),
      dealName: toStr(get(cells, 'Сделка - Название')),
      dealProduct: toStr(get(cells, 'Сделка - Продукт')),
      dealRevenueAmount: toNum(get(cells, 'Сделка - Сумма выручки')),
      dealSource: toStr(get(cells, 'Сделка - Источник сделки')),
      dealStage: toStr(get(cells, 'Сделка - Стадия')),
      dealStageFinal: get(cells, 'Сделка - Стадия') === 'Закрыта',
      dealStageTransitionDate: toStr(get(cells, 'Сделка - Дата перехода объекта на новую стадию')),
      deliveryType: toStr(get(cells, 'Тип поставки')),
      description: toStr(get(cells, 'Сделка - Описание')),
      directSupply: toBool(get(cells, 'Сделка - Прямая поставка')),
      distributor: toStr(get(cells, 'Сделка - Дистрибьютор')),
      finalLicenseAmount: toNum(get(cells, 'Сделка - Итоговая сумма лицензий')),
      finalServiceAmount: toNum(get(cells, 'Сделка - Итоговая сумма услуг')),
      finalServiceAmountByRevenueWithVAT: toNum(get(cells, 'Сделка - Итоговая сумма услуг по выручке (с НДС)')),
      finalServiceAmountWithVAT: toNum(get(cells, 'Сделка - Итоговая сумма услуг (с НДС)')),
      forecast: toStr(get(cells, 'Сделка - Прогноз')),
      identifierRevenue: toStr(get(cells, 'Идентификатор (Выручка)')),
      invoiceAmount: toNum(get(cells, 'Сумма акта')),
      invoiceAmountWithVAT: toNum(get(cells, 'Сумма акта (с НДС)')),
      lastUpdateDate: toStr(get(cells, 'Дата последнего обновления')),
      marketingEvent: toStr(get(cells, 'Сделка - Маркетинговое мероприятие')),
      organization: toStr(get(cells, 'Сделка - Организация')),
      partner: toStr(get(cells, 'Сделка - Партнер по сделке')),
      product: toStr(get(cells, 'Сделка - Продукт')),
      quantity: toNum(get(cells, 'Количество')),
      responsiblePerson: toStr(get(cells, 'Сделка - Ответственный')),
      siteLead: toBool(get(cells, 'Сделка - Лид с сайта')),
      stageTransitionTime: toStr(get(cells, 'Сделка - Дата перехода объекта на новую стадию')),
      totalProductAmount: toNum(get(cells, 'Сделка - Итоговая сумма продуктов')),
      unitOfMeasure: toStr(get(cells, 'Единица измерения')),
    };
  });
}
